mapper.select:
select a.YYYYMM, a.SEL_CODE, CASE WHEN a.SITE='HQ' then '본사' WHEN a.site='VN' then 'VINA' else a.site end SITE, CASE WHEN ACCT_CLASS='AA' then '가공비' WHEN ACCT_CLASS='CC' then '판매관리비' WHEN ACCT_CLASS='BB' then '개발비' else ACCT_CLASS end as ACCT_CLASS, --a.dept, b.dept_name, a.SUB_NAME, a.ITEM_NAME, sum(a.ACCT_AMT) ACCT_AMT, a.EXPEN_SEL from doi_acct_expen a left join doi_dept b on (b.yyyy=substring(a.yyyymm,1,4) and b.sel_code=a.sel_code and b.site=a.site and b.dept=a.dept) where 1=1
and a.YYYYMM = #{yyyymm}
and a.SITE = #{site}
and a.ACCT_CLASS = #{costGubun}
AND a.ACCT_CLASS='AA' AND a.EXPEN_SEL NOT LIKE 'M%'
AND a.ACCT_CLASS='AA' AND a.EXPEN_SEL LIKE 'M%'
group by a.YYYYMM, a.SEL_CODE, CASE WHEN a.SITE='HQ' then '본사' WHEN a.site='VN' then 'VINA' else a.site end, CASE WHEN ACCT_CLASS='AA' then '가공비' WHEN ACCT_CLASS='CC' then '판매관리비' WHEN ACCT_CLASS='BB' then '개발비' else ACCT_CLASS end, --a.dept, b.dept_name, a.SUB_NAME, a.ITEM_NAME, a.EXPEN_SEL order BY 1,2,3,4,5,6,7,8;

select YYYYMM, SEL_CODE, CASE WHEN SITE='HQ' then '본사' WHEN site='VN' then 'VINA' else site end SITE, SUB_NAME, ITEM_NAME, SUM(ACCT_AMT) ACCT_AMT, EXPEN_SEL from DOI_ACCT_EXPEN where 1=1
and YYYYMM = #{yyyymm}
and SITE = #{site}
and acct_class = 'AA' GROUP BY YYYYMM,SEL_CODE,SITE,SUB_NAME,ITEM_NAME,EXPEN_SEL order by SUB_NAME,ITEM_NAME;

select a.YYYYMM, a.SEL_CODE, CASE WHEN a.SITE='HQ' then '본사' WHEN a.SITE='VN' then 'VINA' else a.SITE end SITE, CASE WHEN a.ACCT_CLASS='AA' then '가공비' WHEN a.ACCT_CLASS='CC' then '판매관리비' WHEN a.ACCT_CLASS='BB' then '개발비' else a.ACCT_CLASS end as ACCT_CLASS , b.DEPT_NAME, SUB_NAME, ITEM_NAME, SUM(ACCT_AMT) ACCT_AMT, EXPEN_SEL from DOI_ACCT_EXPEN a inner join doi_dept b on(a.dept=b.dept) where 1=1
and a.YYYYMM = #{yyyymm}
and a.SITE = #{site}
and a.EXPEN_SEL = #{expenSel}
group by a.YYYYMM, a.SEL_CODE, CASE WHEN a.SITE='HQ' then '본사' WHEN a.site='VN' then 'VINA' else a.SITE end, CASE WHEN a.ACCT_CLASS='AA' then '가공비' WHEN a.ACCT_CLASS='CC' then '판매관리비' WHEN a.ACCT_CLASS='BB' then '개발비' else a.ACCT_CLASS end, b.DEPT_NAME,SUB_NAME,ITEM_NAME,EXPEN_SEL order by SUB_NAME,ITEM_NAME;

select YYYYMM, SEL_CODE, DW_SITE as SITE, 구분, 도우모델 as MODEL, MODEL_N_TYPE, BOH_MONTH, IN_MONTH, BONUS_MONTH, EOH_MONTH, OUT_MONTH, LOSS_MONTH, NG_MONTH, 수율제외_MONTH, REWORK진행_MONTH from DOI_PROD_SUBUL where 1=1
and YYYYMM = #{yyyymm}
and DW_SITE = #{site}
and 구분 = #{prodGubun}
order by 1,2,3,model, MODEL_N_TYPE;

select lotrun_no,BOH_MONTH,IN_MONTH,BONUS_MONTH,EOH_MONTH,OUT_MONTH,LOSS_MONTH,NG_MONTH,수율제외_MONTH,material_loss
from DOI_PROD_LOTRUN
where 1=1

    and YYYYMM = #{yyyymm}


    and DW_SITE = #{site}


    and 구분 = #{prodGubun}


    and MODEL_N_TYPE = #{modelNType}

order by lotrun_no;

select YYYYMM, SEL_CODE, SITE, 구분, MODEL, SUM(BOH) BOH, SUM([IN]) INPUT_AMT from doi_expen_matl where 1=1
and YYYYMM = #{yyyymm}
and SITE = #{site}
GROUP BY YYYYMM,SEL_CODE,SITE,구분,MODEL order by YYYYMM,SEL_CODE,SITE,MODEL;

select YYYYMM, SEL_CODE, SITE, 구분, MODEL, BOH, [IN] INPUT_AMT, ACCT_NAME , SUB_NAME , ITEM_NAME from doi_expen_matl where 1=1
and YYYYMM = #{yyyymm}
and SITE = #{site}
and MODEL = #{model}
order by 구분,EXPEN_SEL;

select YYYYMM, SEL_CODE, CASE WHEN SITE='HQ' then '본사' WHEN SITE='VN' then 'VINA' else SITE end SITE, 구분, MODEL, ACCT_NAME, SUB_NAME, ITEM_NAME, SUM(BOH) BOH, SUM([IN]) INPUT_AMT, SUM(EOH) EOH, SUM([OUT]) OUT_AMT, SUM(LOSS) LOSS from doi_cost where 1=1
and YYYYMM = #{yyyymm}
and SITE = #{site}
and ACCT_NAME = #{acctName}
GROUP BY YYYYMM,SEL_CODE, CASE WHEN SITE='HQ' then '본사' WHEN SITE='VN' then 'VINA' else SITE end, 구분,MODEL,ACCT_NAME,SUB_NAME,ITEM_NAME order BY 1,2,3,4,5,6,7,8;

select YYYYMM, SEL_CODE, CASE WHEN SITE='HQ' then '본사' WHEN SITE='VN' then 'VINA' else SITE end SITE, 구분, MODEL, BOH_AMT, IN_AMT, EOH_AMT, OUT_AMT from doi_stock_cost where 1=1 and sel_code = 'ACTUAL'
and YYYYMM = #{yyyymm}
and SITE = #{site}
and 구분 = #{gubun}
and BOH_AMT+IN_AMT+EOH_AMT+OUT_AMT > 0 order BY 1,2,3,4,5;
